import React from "react";
import PropTypes from "prop-types";
import type { Reset } from "../../types/filters/filters";

/**
 * Clear input button.
 *
 * @param {object} props React props.
 * @return {object} - React component.
 */
function Finder__Reset(props: Reset) {
  const isDisabled = props.disabled ?? false;
  const label = props.label ?? "Clear all filters";
  const buttonClassName = props.className
  ? `v26-finder__reset ${props.className}`
  : "v26-finder__reset";
  const resetIconClassName = props.site
    ? "fa fa-times icon"
    : "fa-sharp fa-solid fa-xmark icon";
  if (props.matrixState) {
    return (
      <a href="?" className={buttonClassName} type="button">
        <span className={resetIconClassName} />
        <span className="v26-finder__reset__text">{label}</span>
      </a>
    );
  } else {
    return (
      <button
        className={buttonClassName}
        disabled={isDisabled}
        aria-disabled={isDisabled}
        type="button"
        onClick={() => {
          if (!isDisabled) props.clear(props.resetSort);
        }}
      >
        {props.site === 'city' ? (
          <>
            <span className="v26-finder__reset__text">{label}</span>
            <span className={resetIconClassName} />
          </>
        ) : (
          <>
            <span className={resetIconClassName} />
            <span className="v26-finder__reset__text">{label}</span>
          </>
        )}
      </button>
    );
  }
}

Finder__Reset.propTypes = {
  clear: PropTypes.func,
  resetSort: PropTypes.bool,
  matrixState: PropTypes.bool,
};

export default Finder__Reset;
